class MathHelper:
    @static
    PI: float = 3.14159

    @virtual
    def compute(self, x: int) -> int:
        return x * 2

def clamp(value: int, min_val: int, max_val: int) -> int:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

def sign(value: int) -> int:
    if value > 0:
        return 1
    if value < 0:
        return -1
    return 0

